 72→// ── OmegA message with streaming ─────────────────────────────────
 73→function OmegaMsg({ text, animate, timestamp }: { text: string; animate: boolean; timestamp?: string }) {
 74→  const streaming = animate;
 75→  const [copied, setCopied] = useState(false);
 76→
 77→  const copy = () => {
 78→    navigator.clipboard.writeText(text).then(() => {
 79→      setCopied(true);
 80→      setTimeout(() => setCopied(false), 2000);
 81→    });
 82→  };
 83→
 84→  return (
 85→    <div className={s.msgOmega}>
 86→      <span className={s.omegaGlyph}>Ω</span>
 87→      <div className={s.omegaBody}>
 88→        <div className={`${s.omegaText} ${streaming ? s.streaming : ""}`}>
 89→          <ReactMarkdown remarkPlugins={[remarkGfm]} components={mdComponents}>{text}</ReactMarkdown>
 90→          {streaming && <span className={s.cursor} />}
 91→        </div>
 92→        {!streaming && (
 93→          <div className={s.omegaFooter}>
 94→            {timestamp && <span className={s.msgTimestamp}>{new Date(timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>}
 95→            <button
 96→              className={s.copyBtn}
 97→              onClick={copy}
 98→              title="Copy"
 99→              aria-label={copied ? "Copied to clipboard" : "Copy response"}
100→            >
101→              {copied ? "✓ Copied" : "Copy"}
102→            </button>
103→          </div>
104→        )}
105→      </div>
106→    </div>
107→  );
108→}
