32→export async function chatStream(
33→  req: ChatRequest, 
34→  onChunk: (text: string) => void,
35→  onStatus?: (text: string) => void
36→): Promise<{ sessionId?: string }> {
37→  const res = await fetch('/api/chat', {
38→    method: 'POST',
39→    headers: { 'Content-Type': 'application/json' },
40→    body: JSON.stringify(req),
41→  });
42→
43→  if (!res.ok) {
44→    const body = await res.json().catch(() => ({ error: res.statusText }));
45→    throw new Error((body as { error?: string }).error ?? `${res.status}`);
46→  }
47→
48→  const sessionId = res.headers.get('X-Session-Id') || undefined;
49→
50→  if (!res.body) throw new Error("No response body");
51→
52→  const reader = res.body.getReader();
53→  const decoder = new TextDecoder();
54→  let buffer = "";
55→
56→  while (true) {
57→    const { value, done } = await reader.read();
58→    if (done) break;
59→    const chunkText = decoder.decode(value, { stream: true });
60→    buffer += chunkText;
61→
62→    // Split by SSE double newline if it looks like status events are active
63→    while (buffer.includes('\n\n')) {
64→      const idx = buffer.indexOf('\n\n');
65→      const line = buffer.slice(0, idx).trim();
66→      if (line.startsWith('data: {"type":"status"')) {
67→        try {
68→          const json = JSON.parse(line.slice(5));
69→          if (onStatus) onStatus(json.text);
70→          buffer = buffer.slice(idx + 2);
71→          continue;
72→        } catch {
73→          // fallback if parse fails
74→        }
75→      }
76→      break; // stop if front of buffer isn't a status event
77→    }
78→
79→    if (buffer && !buffer.startsWith('data: {"type":"status"')) {
80→      onChunk(buffer);
81→      buffer = "";
82→    }
83→  }
84→  
85→  // Flush remaining buffer
86→  const final = decoder.decode();
87→  buffer += final;
88→  if (buffer) onChunk(buffer);
89→
90→  return { sessionId };
91→}
