146→function formatRelativeTime(dateStr: string) {
147→  if (!dateStr) return "";
148→  const diff = Math.max(0, Date.now() - new Date(dateStr).getTime());
149→  const minutes = Math.floor(diff / 60000);
150→  if (minutes < 1) return `just now`;
151→  if (minutes < 60) return `${minutes}m ago`;
152→  const hours = Math.floor(minutes / 60);
153→  if (hours < 24) return `${hours}h ago`;
154→  const days = Math.floor(hours / 24);
155→  if (days === 1) return `yesterday`;
156→  return `${days}d ago`;
157→}
