/* ── Root ───────────────────────────────────────────────────────── */
.root {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  z-index: 1;
}

/* ── Landing ────────────────────────────────────────────────────── */
.landing {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  padding-top: 15vh;
  gap: 0;
  padding-bottom: 80px;
  position: relative;
  overflow-y: auto;
  overflow-x: hidden;
}

.vignettePulse {
  position: fixed;
  inset: 0;
  pointer-events: none;
  background: radial-gradient(circle at center, rgba(139, 92, 246, 0.08) 0%, transparent 65%);
  animation: vignette-breathe 6s ease-in-out infinite;
  pointer-events: none;
  z-index: 0;
}

@keyframes vignette-breathe {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 1; }
}

.heroSection {
  display: flex;
  flex-direction: column;
  align-items: center;
  position: relative;
  z-index: 1;
  margin-bottom: var(--space-6);
}

.landingOmega {
  font-family: 'Orbitron', sans-serif;

